import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { 
  HiHome, 
  HiOutlineClipboardList, 
  HiOutlineCalendar, 
  HiOutlineUser, 
  HiOutlineCog 
} from 'react-icons/hi';

const BottomNavigation = () => {
  const { t } = useTranslation();
  const location = useLocation();

  const navItems = [
    { path: '/', label: t('home'), icon: HiHome },
    { path: '/medicines', label: t('medicines'), icon: HiOutlineClipboardList },
    { path: '/availability', label: t('availability'), icon: HiOutlineCalendar },
    { path: '/profile', label: t('profile'), icon: HiOutlineUser },
    { path: '/settings', label: t('settings'), icon: HiOutlineCog }
  ];

  return (
    <nav 
      className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 shadow-2xl z-50 backdrop-blur-sm"
      style={{
        background: 'linear-gradient(135deg, rgba(255,255,255,0.95) 0%, rgba(248,250,252,0.98) 100%)',
        backdropFilter: 'blur(20px)',
        borderTop: '1px solid rgba(226,232,240,0.8)'
      }}
      role="navigation"
      aria-label="Main navigation"
    >
      <div className="flex justify-between items-center h-20 px-8 max-w-md mx-auto">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path;
          
          return (
            <Link
              key={item.path}
              to={item.path}
              className={`flex flex-col items-center justify-center py-2 px-3 rounded-2xl transition-all duration-300 ease-out group no-underline focus-ring relative ${
                isActive
                  ? 'transform scale-110'
                  : 'hover:scale-105'
              }`}
              style={{ textDecoration: 'none' }}
              aria-label={`Navigate to ${item.label}`}
              tabIndex={0}
            >
              {/* Modern floating icon container */}
              <div className={`flex items-center justify-center w-12 h-12 rounded-full transition-all duration-300 ease-out relative ${
                isActive 
                  ? 'bg-gradient-to-r from-blue-500 to-blue-600 shadow-lg shadow-blue-500/30 transform -translate-y-1' 
                  : 'bg-gray-50 group-hover:bg-blue-50 group-hover:shadow-md group-hover:shadow-blue-500/20'
              }`}>
                <Icon className={`transition-all duration-300 ease-out ${
                  isActive 
                    ? 'text-xl text-white' 
                    : 'text-xl text-gray-500 group-hover:text-blue-600'
                }`} />
                
                {/* Active indicator dot */}
                {isActive && (
                  <div className="absolute -bottom-2 w-1 h-1 bg-blue-600 rounded-full animate-pulse"></div>
                )}
              </div>
              
              {/* Modern label */}
              <span className={`text-xs font-medium mt-1 transition-all duration-300 ease-out ${
                isActive 
                  ? 'text-blue-600 font-semibold' 
                  : 'text-gray-500 group-hover:text-blue-600'
              }`}>
                {item.label}
              </span>
            </Link>
          );
        })}
      </div>
    </nav>
  );
};

export default BottomNavigation;
